sys_sg_data_item.query_condition_script:
(function getQueryString(input){
    const currentUser = gs.getUserID();

    return 'u_requested_by!=' + currentUser + '^u_status=In progress^parent.parentISEMPTY^parent.u_task_requester=' + currentUser + '^ORparent.primary_office.tasking_authoritiesLIKE' + currentUser + '^NQu_requested_by!=' + currentUser + '^u_status=In progress^parent.parentISNOTEMPTY^parent.u_task_requester=' + currentUser + '^ORparent.primary_assignee.tasking_authoritiesLIKE' + currentUser;

})(input)
